161	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
162	
163	  // Dragon material
164	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
165	
166	  // Both clauses: enchantment >= 8 wins (50% rule)
167	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G");
168	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G yields payout 400 G");
169	
170	  // Cap based on unmodified insurance sum
171	  it.todo("cursed sword has cap 2000 G (based on unmodified insurance value)");
172	  it.todo("sword + 3 runes policy has insurance sum 1750 G (block discount doesn't affect insurance sum)");
173	
174	  // Cap exhaustion across multiple claims
175	  it.todo("sword (cap 2000): first claim 1500 G yields payout 1400 G, remaining cap 600 G");
176	  it.todo("sword (cap 2000) after first 1400 G payout: second claim 1500 G yields payout 600 G, remaining cap 0");
177	
178	  // Multiple items of same type
179	  it.todo("policy with two swords: dragon attack on both treats each as separate damage with own deductible");
180	
181	  // Rounding for payout
182	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G (in MHPCO's favor)");
183	});
