186	  it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
187	  it.todo("quote step result contains premium (integer)");
188	  it.todo("claim step result contains payout and remainingCap (integers)");
189	  it.todo("claim references policy by zero-based step index");
190	
191	  // Error cases
192	  it.todo("unknown item type in quote exits non-zero with stderr message and no results on stdout");
193	  it.todo("claim referencing item not in policy exits non-zero with stderr message");
194	  it.todo("claim with negative damage amount exits non-zero with stderr message");
195	  it.todo("claim with more damage entries of a type than policy covers exits non-zero");
196	});
